from pathlib import Path
import re

def verify(workspace_path, external_services_path=None):
    ws = Path(workspace_path)

    # Find the receiving log xlsx file
    xlsx_files = list(ws.rglob('*.xlsx'))
    log_file = None
    for f in xlsx_files:
        if 'receiv' in f.name.lower() or 'log' in f.name.lower():
            log_file = f
            break
    if log_file is None and xlsx_files:
        log_file = xlsx_files[0]

    if log_file is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'No .xlsx file found in workspace.'}

    try:
        import openpyxl
        wb = openpyxl.load_workbook(log_file)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Failed to open {log_file.name}: {e}'}

    best_result = None
    best_score = -1

    for ws_sheet in wb.worksheets:
        rows = list(ws_sheet.iter_rows(values_only=True))
        if len(rows) < 2:
            continue

        # Find header row
        header_row_idx = None
        headers = []
        for i, row in enumerate(rows):
            non_none = [c for c in row if c is not None]
            if len(non_none) >= 3:
                header_row_idx = i
                headers = [str(c).strip().lower() if c is not None else '' for c in row]
                break

        if header_row_idx is None:
            continue

        def find_col(patterns):
            results = []
            for idx, h in enumerate(headers):
                for p in patterns:
                    if p in h:
                        results.append(idx)
                        break
            return results

        expected_pallet_cols = find_col(['expected pallet'])
        actual_pallet_cols = find_col(['actual pallet'])
        pallet_cols = find_col(['pallet'])
        actual_case_cols = find_col(['actual case'])
        case_cols = find_col(['case'])
        temp_cols = find_col(['temp'])
        variance_cols = find_col(['variance'])
        lot_cols = find_col(['lot'])
        disposition_cols = find_col(['disposition'])
        status_cols = find_col(['status'])

        data_rows = rows[header_row_idx + 1:]
        for row in data_rows:
            row_str_list = [str(c).strip() if c is not None else '' for c in row]
            row_lower = ' '.join(row_str_list).lower()

            non_empty = [c for c in row if c is not None and str(c).strip() != '']
            if len(non_empty) < 3:
                continue

            def get_vals(col_indices):
                vals = []
                for ci in col_indices:
                    if ci < len(row) and row[ci] is not None:
                        vals.append(row[ci])
                return vals

            def num_eq(val, target, tol=0.5):
                try:
                    return abs(float(val) - target) < tol
                except (ValueError, TypeError):
                    s = str(val).replace('\u2212', '-').replace('\u2013', '-').replace('\u2014', '-')
                    m = re.search(r'-?\d+\.?\d*', s)
                    if m:
                        try:
                            return abs(float(m.group()) - target) < tol
                        except:
                            pass
                    return False

            # Check Expected Pallets = 24
            expected_pallet_ok = False
            for v in get_vals(expected_pallet_cols):
                if num_eq(v, 24, 0.5):
                    expected_pallet_ok = True
            if not expected_pallet_ok:
                for v in get_vals(pallet_cols):
                    if num_eq(v, 24, 0.5):
                        expected_pallet_ok = True
                        break
            if not expected_pallet_ok:
                for v in row:
                    if v is not None and num_eq(v, 24, 0.5):
                        expected_pallet_ok = True
                        break

            # Check Actual Pallets = 24
            actual_pallet_ok = False
            for v in get_vals(actual_pallet_cols):
                if num_eq(v, 24, 0.5):
                    actual_pallet_ok = True
            if not actual_pallet_ok:
                for v in get_vals(pallet_cols):
                    if num_eq(v, 24, 0.5):
                        actual_pallet_ok = True
                        break
            if not actual_pallet_ok:
                for v in row:
                    if v is not None and num_eq(v, 24, 0.5):
                        actual_pallet_ok = True
                        break

            pallets_ok = expected_pallet_ok and actual_pallet_ok

            # Check Actual Cases = 474
            cases_ok = False
            for v in get_vals(actual_case_cols):
                if num_eq(v, 474, 0.5):
                    cases_ok = True
            if not cases_ok:
                for v in get_vals(case_cols):
                    if num_eq(v, 474, 0.5):
                        cases_ok = True
                        break
            if not cases_ok:
                for v in row:
                    if v is not None and num_eq(v, 474, 0.5):
                        cases_ok = True
                        break

            # Check temps: need -4.5, -6.0 (or -6), -7.5
            temp_vals_raw = get_vals(temp_cols)
            if not temp_vals_raw:
                temp_vals_raw = [v for v in row if v is not None]

            temp_nums = []
            for v in temp_vals_raw:
                try:
                    temp_nums.append(float(v))
                except (ValueError, TypeError):
                    s = str(v).replace('\u2212', '-').replace('\u2013', '-').replace('\u2014', '-')
                    matches = re.findall(r'-?\d+\.?\d*', s)
                    for m in matches:
                        try:
                            temp_nums.append(float(m))
                        except:
                            pass

            has_neg4_5 = any(abs(t - (-4.5)) < 0.15 for t in temp_nums)
            has_neg6 = any(abs(t - (-6.0)) < 0.15 for t in temp_nums)
            has_neg7_5 = any(abs(t - (-7.5)) < 0.15 for t in temp_nums)
            temps_ok = has_neg4_5 and has_neg6 and has_neg7_5

            # Check variance = -6
            variance_ok = False
            for v in get_vals(variance_cols):
                if num_eq(v, -6, 0.5):
                    variance_ok = True
            if not variance_ok:
                for v in get_vals(variance_cols):
                    s = str(v).replace('\u2212', '-').replace('\u2013', '-')
                    if re.search(r'-\s*6(\.0)?\s*$', s.strip()):
                        variance_ok = True

            # Check lot code A-20260519-01
            lot_ok = False
            for v in get_vals(lot_cols):
                if 'a-20260519-01' in str(v).lower():
                    lot_ok = True
            if not lot_ok:
                if 'a-20260519-01' in row_lower:
                    lot_ok = True

            # Check disposition: quarantine/quarantined AND H-Q
            disp_vals = get_vals(disposition_cols)
            disp_text = ' '.join(str(v) for v in disp_vals).lower() if disp_vals else row_lower
            disp_text_norm = disp_text.replace('\u2212', '-').replace('\u2013', '-')
            quarantine_ok = bool(re.search(r'quarantin', disp_text_norm))
            hq_ok = bool(re.search(r'h[\-\s]?q', disp_text_norm))

            # Check status: P2 - Compound event (with flexible dash)
            status_vals = get_vals(status_cols)
            status_text = ' '.join(str(v) for v in status_vals).lower() if status_vals else row_lower
            status_text_norm = status_text.replace('\u2212', '-').replace('\u2013', '-').replace('\u2014', '-')
            has_p2 = bool(re.search(r'p\s*2', status_text_norm))
            has_compound = bool(re.search(r'compound\s*event', status_text_norm))
            status_ok = has_p2 and has_compound

            checks = [
                ('Expected Pallets = 24', expected_pallet_ok),
                ('Actual Pallets = 24', actual_pallet_ok),
                ('Actual Cases = 474', cases_ok),
                ('Temp -4.5', has_neg4_5),
                ('Temp -6.0/-6', has_neg6),
                ('Temp -7.5', has_neg7_5),
                ('Variance (Cases) = -6', variance_ok),
                ('Lot Code A-20260519-01', lot_ok),
                ('Disposition: quarantine', quarantine_ok),
                ('Disposition: H-Q', hq_ok),
                ('Status: P2', has_p2),
                ('Status: Compound event', has_compound),
            ]

            passed_checks = [name for name, ok in checks if ok]
            failed_checks = [name for name, ok in checks if not ok]
            score = len(passed_checks) / len(checks)

            if score > best_score:
                best_score = score
                if not failed_checks:
                    best_result = {
                        'pass': True,
                        'score': 1.0,
                        'feedback': f'All required fields found in {log_file.name}: {", ".join(passed_checks)}.'
                    }
                else:
                    best_result = {
                        'pass': False,
                        'score': score,
                        'feedback': f'In {log_file.name}, found: {", ".join(passed_checks)}. Missing: {", ".join(failed_checks)}. Row values: {row_str_list}'
                    }

    if best_result is not None and best_score >= 0.4:
        return best_result

    # Fallback: read all text from all files and do loose matching
    candidates = set()
    for pattern in ['*.txt', '*.md', '*.csv', '*.json', '*.log']:
        candidates.update(ws.glob(pattern))
    candidates.update(ws.rglob('*receiv*'))
    candidates.update(ws.rglob('*log*'))
    candidates.update(ws.rglob('*.xlsx'))
    candidates.update(ws.rglob('*.csv'))
    candidates.update(ws.rglob('*.txt'))
    candidates.update(ws.rglob('*.md'))

    all_text = ''
    files_read = []

    for f in candidates:
        try:
            if f.is_dir():
                continue
            if f.suffix.lower() == '.xlsx':
                import openpyxl as oxl
                wb2 = oxl.load_workbook(f)
                for s in wb2.worksheets:
                    for row in s.iter_rows(values_only=True):
                        for cell in row:
                            if cell is not None:
                                all_text += str(cell) + ' '
                files_read.append(str(f.name))
            elif f.suffix.lower() == '.docx':
                from docx import Document
                doc = Document(f)
                content = ' '.join([p.text for p in doc.paragraphs])
                all_text += content + ' '
                files_read.append(str(f.name))
            else:
                content = f.read_text(encoding='utf-8', errors='ignore')
                all_text += content + ' '
                files_read.append(str(f.name))
        except Exception:
            continue

    if not all_text.strip():
        return {'pass': False, 'score': 0.0, 'feedback': 'No readable content found in workspace.'}

    normalized = all_text.replace('\u2212', '-').replace('\u2013', '-').replace('\u2014', '-').replace('\u00b0', ' ')
    text_lower = normalized.lower()

    checks = []

    # 1. pallets 24
    checks.append(('Pallets 24', '24' in text_lower))

    # 2. cases 474
    checks.append(('Actual Cases 474', '474' in text_lower))

    # 3. temps
    checks.append(('Temp -4.5', bool(re.search(r'-\s*4\.5', normalized))))
    checks.append(('Temp -6.0/-6', bool(re.search(r'-\s*6\.0', normalized) or re.search(r'-\s*6(?![\d.])', normalized))))
    checks.append(('Temp -7.5', bool(re.search(r'-\s*7\.5', normalized))))

    # 4. variance -6
    checks.append(('Variance -6', bool(re.search(r'-\s*6', normalized))))

    # 5. lot code
    checks.append(('Lot Code A-20260519-01', 'a-20260519-01' in text_lower))

    # 6. quarantine
    checks.append(('Disposition: quarantine', bool(re.search(r'quarantin', text_lower))))

    # 7. H-Q
    checks.append(('Disposition: H-Q', bool(re.search(r'h[\-\s]?q', text_lower))))

    # 8. P2
    checks.append(('Status: P2', bool(re.search(r'p[\-\s]?2', text_lower))))

    # 9. Compound event
    checks.append(('Status: Compound event', bool(re.search(r'compound\s*event', text_lower))))

    passed_checks = [name for name, ok in checks if ok]
    failed_checks = [name for name, ok in checks if not ok]
    score = len(passed_checks) / len(checks) if checks else 0.0

    if not failed_checks:
        return {'pass': True, 'score': 1.0, 'feedback': f'All required fields found (fallback text search): {", ".join(passed_checks)}. Files: {", ".join(files_read[:10])}'}
    else:
        return {'pass': False, 'score': score, 'feedback': f'Missing: {", ".join(failed_checks)}. Found: {", ".join(passed_checks)}. Files: {", ".join(files_read[:10])}'}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check slack_data.json'}

    slack_path = Path(external_services_path) / 'slack_data.json'
    if not slack_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found at external_services_path'}

    with open(slack_path, 'r', encoding='utf-8') as f:
        data = json.load(f)

    # Find the #dc-escalations channel
    channels = data.get('channels', {})
    escalation_channel_id = None
    for cid, cinfo in channels.items():
        cname = str(cinfo.get('name', '')).lower().strip()
        if cname == 'dc-escalations':
            escalation_channel_id = cid
            break

    if escalation_channel_id is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'Could not find #dc-escalations channel in slack_data.json. Channels found: ' + str([c.get('name', '') for c in channels.values()])}

    # Get messages in that channel
    messages_by_channel = data.get('messages', {})
    channel_messages = messages_by_channel.get(escalation_channel_id, [])

    if not channel_messages:
        return {'pass': False, 'score': 0.0, 'feedback': f'No messages found in #dc-escalations channel (channel ID: {escalation_channel_id})'}

    # Score each message to find the best candidate
    best_msg = None
    best_score = -1

    for msg in channel_messages:
        text = str(msg.get('text', ''))
        text_lower = text.lower()
        score = 0
        if text_lower.lstrip().startswith('p2 escalation'):
            score += 5
        if '2026-05-20-001' in text:
            score += 5
        if 'compound' in text_lower:
            score += 3
        if 'director of supply chain' in text_lower:
            score += 3
        if 'awaiting director decision' in text_lower:
            score += 3
        if score > best_score:
            best_score = score
            best_msg = msg

    if best_msg is None or best_score <= 0:
        texts_preview = [str(m.get('text', ''))[:80] for m in channel_messages[:5]]
        return {'pass': False, 'score': 0.0, 'feedback': f'No plausible escalation message found in #dc-escalations among {len(channel_messages)} messages. Previews: {texts_preview}'}

    text = str(best_msg.get('text', ''))
    text_lower = text.lower()

    failures = []
    details = []

    # (1) Must begin with 'P2 escalation. Compound.' [exact string, 'compound event' not acceptable]
    # The rubric says exact string 'P2 escalation. Compound.' at the start.
    # We check case-insensitively for leniency, and allow minor whitespace variations,
    # but 'compound' must appear as a standalone word (not 'compound event' replacing it).
    # The key distinction: must say 'Compound' (with period/punctuation after), NOT 'Compound event'.
    start_pattern = re.compile(r'(?i)^\s*p2\s+escalation\.\s*compound\s*\.', re.DOTALL)
    if start_pattern.search(text):
        # Additionally verify it doesn't say 'compound event' right at the start
        bad_pattern = re.compile(r'(?i)^\s*p2\s+escalation\.\s*compound\s+event', re.DOTALL)
        if bad_pattern.search(text):
            failures.append(f"(1) Message begins with 'P2 escalation. Compound event...' but rubric requires exactly 'P2 escalation. Compound.' (not 'compound event'). Start: '{text[:80]}...'")
        else:
            details.append("(1) Message begins with 'P2 escalation. Compound.' \u2713")
    else:
        failures.append(f"(1) Message must begin with 'P2 escalation. Compound.' but starts with: '{text[:80]}...'")

    # (2) Must contain manifest number '2026-05-20-001'
    if '2026-05-20-001' in text:
        details.append("(2) Manifest number '2026-05-20-001' found \u2713")
    else:
        failures.append("(2) Manifest number '2026-05-20-001' not found in message")

    # (3) Must contain the exact phrase 'Escalated to Director of Supply Chain.'
    # Be loose: case-insensitive, allow with or without trailing period
    if re.search(r'(?i)escalated\s+to\s+director\s+of\s+supply\s+chain\.?', text):
        details.append("(3) 'Escalated to Director of Supply Chain.' found \u2713")
    else:
        failures.append("(3) Exact phrase 'Escalated to Director of Supply Chain.' not found in message")

    # (4) Must contain the exact phrase 'Incident report: awaiting Director decision.'
    # Be loose: case-insensitive, allow with or without trailing period, flexible colon/space
    if re.search(r'(?i)incident\s+report\s*[:\-]\s*awaiting\s+director\s+decision\.?', text):
        details.append("(4) 'Incident report: awaiting Director decision.' found \u2713")
    else:
        failures.append("(4) Exact phrase 'Incident report: awaiting Director decision.' not found in message")

    if failures:
        feedback = 'Escalation message verification failures: ' + '; '.join(failures)
        if details:
            feedback += ' | Passed: ' + '; '.join(details)
        feedback += f' | Message preview: {text[:400]}'
        return {'pass': False, 'score': 0.0, 'feedback': feedback}

    return {'pass': True, 'score': 1.0, 'feedback': 'All #dc-escalations message criteria satisfied. ' + '; '.join(details)}

from pathlib import Path
import json
import re

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check mailbox.json'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'mailbox.json not found'}

    with open(mailbox_path, 'r', encoding='utf-8') as f:
        data = json.load(f)

    sent_emails = [e for e in data.get('emails', []) if e.get('folder', '').lower() == 'sent']

    if not sent_emails:
        return {'pass': False, 'score': 0.0, 'feedback': 'No sent emails found in mailbox.json'}

    # Find the escalation email - look for one addressed to daniel.reyes
    matching_email = None
    for email in sent_emails:
        to_addr = (email.get('to_addr') or email.get('to') or '').lower()
        if 'daniel.reyes@prairiestar.com' in to_addr:
            matching_email = email
            break

    if matching_email is None:
        # Fallback: look for email with P2 in subject or relevant content
        for email in sent_emails:
            subject = (email.get('subject') or '').lower()
            body = (email.get('body_text') or email.get('body') or '').lower()
            if 'p2' in subject or ('quarantine' in body and 'h-q' in body):
                matching_email = email
                break

    if matching_email is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'No escalation email found in sent folder addressed to daniel.reyes@prairiestar.com'}

    failures = []

    # --- Check TO field ---
    to_addr = (matching_email.get('to_addr') or matching_email.get('to') or '').lower().strip()
    if 'daniel.reyes@prairiestar.com' not in to_addr:
        failures.append('To field does not contain daniel.reyes@prairiestar.com')
    else:
        to_emails = re.findall(r'[\w.+-]+@[\w.-]+', to_addr)
        to_emails_filtered = [e for e in to_emails if e != 'daniel.reyes@prairiestar.com']
        if to_emails_filtered:
            failures.append(f'To field contains additional recipients beyond daniel.reyes@prairiestar.com: {to_emails_filtered}')

    # --- Check CC field ---
    cc_addr = (matching_email.get('cc_addr') or matching_email.get('cc') or '').lower().strip()
    cc_emails = re.findall(r'[\w.+-]+@[\w.-]+', cc_addr)
    required_cc = {'carlos.mendoza@prairiestar.com', 'jacob.patel@prairiestar.com'}
    cc_set = set(cc_emails)
    missing_cc = required_cc - cc_set
    extra_cc = cc_set - required_cc
    if missing_cc:
        failures.append(f'CC field missing required recipients: {missing_cc}')
    if extra_cc:
        failures.append(f'CC field contains extra recipients: {extra_cc}')

    # --- Check Subject ---
    subject = matching_email.get('subject') or ''
    subject_lower = subject.lower()
    if 'p2' not in subject_lower:
        failures.append('Subject does not contain P2')
    if 'compound event' not in subject_lower:
        failures.append('Subject does not contain Compound Event')
    if '2026-05-20-001' not in subject:
        failures.append('Subject does not contain 2026-05-20-001')
    if '2026-05-20' not in subject:
        failures.append('Subject does not contain 2026-05-20')

    # --- Check Body ---
    body = matching_email.get('body_text') or matching_email.get('body') or ''
    # Normalize unicode minus signs and en-dashes to regular minus/hyphen
    normalized_body = body.replace('\u2212', '-').replace('\u2013', '-').replace('\u2014', '-').replace('\u00b0', ' ')
    normalized_lower = normalized_body.lower()

    # Temperature readings: -4.5, -6.0 (or -6), -7.5
    if not re.search(r'[-]\s*4\.5', normalized_lower):
        failures.append('Body does not contain temperature reading -4.5 (or \u22124.5)')

    # -6.0 or -6 (but distinguish from -6 in other contexts like variance)
    has_minus6 = bool(re.search(r'[-]\s*6\.0', normalized_lower)) or bool(re.search(r'[-]\s*6(?:\b|\s|f|$|,|\)|\*|\xb0)', normalized_lower))
    if not has_minus6:
        failures.append('Body does not contain temperature reading -6.0 or -6 (or \u22126.0/\u22126)')

    if not re.search(r'[-]\s*7\.5', normalized_lower):
        failures.append('Body does not contain temperature reading -7.5 (or \u22127.5)')

    # Tier 3
    if not re.search(r'tier[\s\-_]*3', normalized_lower):
        failures.append('Body does not contain Tier 3')

    # Variance: -6 cases and 1.25%
    has_variance_cases = bool(re.search(r'[-]\s*6\s*case', normalized_lower)) or \
                         bool(re.search(r'varianc.{0,80}[-]\s*6', normalized_lower)) or \
                         bool(re.search(r'[-]\s*6.{0,30}case', normalized_lower)) or \
                         bool(re.search(r'shortage.{0,30}6', normalized_lower)) or \
                         bool(re.search(r'short.{0,30}6\s*case', normalized_lower)) or \
                         bool(re.search(r'6\s*case.{0,30}short', normalized_lower))
    if not has_variance_cases:
        failures.append('Body does not state variance of -6 cases')

    if '1.25' not in normalized_body:
        failures.append('Body does not state variance percentage 1.25%')
    else:
        # Check if 1.25 is near a percent sign or the word percent
        if not re.search(r'1\.25\s*(%|percent)', normalized_lower):
            failures.append('Body contains 1.25 but not clearly as 1.25%')

    # 'Moderate'
    if 'moderate' not in normalized_lower:
        failures.append('Body does not contain Moderate')

    # 'quarantined to H-Q' - check that quarantined and H-Q are present and near each other
    if 'h-q' not in normalized_lower and 'h\u2011q' not in normalized_lower:
        failures.append('Body does not contain H-Q')
    if 'quarantine' not in normalized_lower and 'quarantined' not in normalized_lower:
        failures.append('Body does not contain quarantine or quarantined')

    # 'Director assessment required' - exact string check (case-insensitive)
    if not re.search(r'director\s+assessment\s+required', normalized_lower):
        failures.append('Body does not contain exact string "Director assessment required"')

    if failures:
        return {'pass': False, 'score': 0.0, 'feedback': 'Email issues: ' + '; '.join(failures)}

    return {'pass': True, 'score': 1.0, 'feedback': 'Email correctly addressed To: daniel.reyes@prairiestar.com, CC: carlos.mendoza and jacob.patel, subject contains P2/Compound Event/2026-05-20-001/2026-05-20, body contains all required content: temps -4.5/-6.0/-7.5, Tier 3, variance -6 cases/1.25%, Moderate, quarantined to H-Q, Director assessment required.'}
